/// <reference path="./manga-provider.d.ts" />

class Provider {
    private readonly hipercool = new HiperCoolProvider()
    private readonly tiamanhwa = new TiaManhwaProvider()

    getSettings(): Settings {
        return {
            supportsMultiLanguage: false,
            supportsMultiScanlator: false,
        }
    }

    async search(opts: QueryOptions): Promise<SearchResult[]> {
        const [hiperResults, tiaResults] = await Promise.all([
            this.hipercool.search(opts),
            this.tiamanhwa.search(opts),
        ])
        return [...hiperResults, ...tiaResults]
    }

    async findChapters(mangaId: string): Promise<ChapterDetails[]> {
        const [source, id] = this.splitPrefixedId(mangaId)
        if (!source || !id) return []
        if (source === 'hipercool') return this.hipercool.findChapters(id)
        if (source === 'tiamanhwa') return this.tiamanhwa.findChapters(id)
        return []
    }

    async findChapterPages(chapterId: string): Promise<ChapterPage[]> {
        if (chapterId.startsWith('https://hiper.cool/')) return this.hipercool.findChapterPages(chapterId)
        if (chapterId.startsWith('https://tiamanhwa.com/')) return this.tiamanhwa.findChapterPages(chapterId)
        return []
    }

    private splitPrefixedId(value: string): [string | null, string | null] {
        const idx = String(value || '').indexOf(':')
        if (idx === -1) return [null, null]
        return [value.slice(0, idx), value.slice(idx + 1)]
    }
}

class HiperCoolProvider {
    private readonly baseUrl = "https://hiper.cool"
    private readonly anilistUrl = "https://graphql.anilist.co"
    private readonly anilistMappingsUrl = "https://raw.githubusercontent.com/Fribb/anime-lists/master/anime-list-mini.json"
    private anilistMappingsCache: any[] | null = null


    private readonly selectors = {
        search: {
            container: ".search-wrap .c-tabs-item, .c-tabs-item, .page-item-detail, .row.c-tabs-item",
            title: "h3 a, .post-title h3 a, .post-title a, h2 a",
            image: "img"
        },
        chapters: {
            list: ".wp-manga-chapter",
            listingWrap: ".listing-chapters_wrap .wp-manga-chapter",
            link: "a"
        },
        pages: {
            content: ".reading-content img",
            reading: ".page-break img, .text-left img, .reading-content .page-break img",
            page: ".entry-content img, .chapter-content img, .wp-manga-chapter-img"
        }
    }

    private readonly defaultHeaders = {
        "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/122.0.0.0 Safari/537.36",
        "Accept": "text/html,application/xhtml+xml,application/xml;q=0.9,image/webp,*/*;q=0.8"
    }

    private readonly patterns = {
        mangaId: /\/manga\/([^\/]+)\/?/i,
        chapterUrl: /capitulo-([^\/]+)/i
    }

    async search(opts: QueryOptions): Promise<SearchResult[]> {
        const query = String(opts?.query || '').trim()
        if (!query) return []

        try {
            const aliasQueries = await this.buildAliasQueries(query)
            const queryInfo = this.buildQueryInfo(query)
            const candidates = new Map<string, { item: SearchResult; score: number }>()

            for (const aliasQuery of aliasQueries) {
                const partial = await this.searchHiperCool(aliasQuery)
                for (const item of partial) {
                    const score = this.scoreResult(item, queryInfo)
                    if (score < 60) continue
                    const current = candidates.get(item.id)
                    if (!current || score > current.score) {
                        candidates.set(item.id, { item, score })
                    }
                }
            }

            return Array.from(candidates.values())
                .sort((a, b) => b.score - a.score)
                .map(entry => entry.item)
        } catch {
            return []
        }
    }

    private async buildAliasQueries(query: string): Promise<string[]> {
        const map = new Map<string, string>()
        const add = (value: string) => {
            const raw = String(value || '').trim()
            const key = this.normalizeText(raw)
            if (!raw || !key || map.has(key)) return
            map.set(key, raw)
        }

        add(query)
        const aliases = await this.fetchAniListTitles(query)
        for (const alias of aliases) add(alias)

        return Array.from(map.values()).slice(0, 5)
    }

    private async fetchAniListTitles(query: string): Promise<string[]> {
        try {
            const gql = `query ($search: String) {\n  Media(search: $search, type: MANGA) {\n    title { romaji english native }\n    synonyms\n  }\n}`
            const response = await fetch(this.anilistUrl, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Accept': 'application/json',
                },
                body: JSON.stringify({ query: gql, variables: { search: query } }),
            })
            if (!response.ok) return []
            const data = await response.json()
            const media = data?.data?.Media
            if (!media) return []

            const rawTitles = [media.title?.romaji, media.title?.english, media.title?.native, ...(media.synonyms || [])]
            const map = new Map<string, string>()
            for (const title of rawTitles) {
                const raw = String(title || '').trim()
                const key = this.normalizeText(raw)
                if (!raw || !key || map.has(key)) continue
                map.set(key, raw)
            }
            return Array.from(map.values())
        } catch {
            return []
        }
    }

    private async searchHiperCool(query: string): Promise<SearchResult[]> {
        const searchUrl = `${this.baseUrl}/?s=${encodeURIComponent(query)}&post_type=wp-manga`
        const response = await this.fetchWithRetry(searchUrl)
        if (!response) return []

        const html = await response.text()
        const $ = LoadDoc(html)
        const results: SearchResult[] = []
        const seen = new Set<string>()

        $(this.selectors.search.container).each((_: number, element: any) => {
            const item = this.parseSearchResultItem(element)
            if (!item || seen.has(item.id)) return
            seen.add(item.id)
            results.push(item)
        })

        if (results.length === 0) {
            $("a").each((_: number, element: any) => {
                const href = String(element.attr("href") || "").trim()
                const title = String(element.attr("title") || element.text() || "").trim()
                if (!href || !title) return
                if (!/\/manga\//i.test(href) || /\/capitulo-/i.test(href)) return
                const mangaId = this.extractMangaId(href)
                if (!mangaId || seen.has(mangaId)) return
                seen.add(mangaId)
                results.push({
                    id: `hipercool:${mangaId}`,
                    title,
                    synonyms: this.buildSynonyms(title, mangaId),
                    image: undefined,
                })
            })
        }

        return results
    }

    private async fetchWithRetry(url: string, retries: number = 1): Promise<Response | null> {
        for (let attempt = 0; attempt <= retries; attempt++) {
            try {
                const response = await fetch(url, { headers: this.defaultHeaders })
                if (response.ok) return response
                if (attempt === retries) return null
            } catch {
                if (attempt === retries) return null
            }
        }
        return null
    }

    private parseSearchResultItem(element: any): SearchResult | null {
        const linkElement = element.find(this.selectors.search.title)
        if (linkElement.length() === 0) return null

        const href = String(linkElement.attr("href") || "").trim()
        const title = String(linkElement.attr("title") || linkElement.text() || "").trim()
        if (!href || !title) return null
        if (/\/capitulo-/i.test(href)) return null

        const mangaId = this.extractMangaId(href)
        if (!mangaId) return null

        const imageUrl = this.extractImageUrl(element)
        return {
            id: `hipercool:${mangaId}`,
            title,
            synonyms: this.buildSynonyms(title, mangaId),
            image: imageUrl,
        }
    }

    private buildSynonyms(title: string, mangaId: string): string[] {
        const values = [title, mangaId.replace(/-/g, ' '), mangaId]
        const map = new Map<string, string>()
        for (const value of values) {
            const raw = String(value || '').trim()
            const key = this.normalizeText(raw)
            if (!raw || !key || map.has(key)) continue
            map.set(key, raw)
        }
        return Array.from(map.values())
    }

    private buildQueryInfo(query: string): { normalized: string; tokens: string[] } {
        const normalized = this.normalizeText(query)
        const tokens = normalized.split(' ').filter(Boolean)
        return { normalized, tokens }
    }

    private scoreResult(item: SearchResult, queryInfo: { normalized: string; tokens: string[] }): number {
        const texts = [item.title, ...(item.synonyms || [])]
            .map(value => this.normalizeText(String(value || '')))
            .filter(Boolean)
        if (texts.length === 0 || queryInfo.tokens.length === 0) return 0

        let best = 0
        for (const text of texts) {
            let score = 0
            if (text === queryInfo.normalized) score = 120
            else if (text.replace(/\s+/g, '') === queryInfo.normalized.replace(/\s+/g, '')) score = 115
            else if (text.startsWith(queryInfo.normalized)) score = 105
            else if (text.includes(queryInfo.normalized)) score = 95
            else {
                const tokenHits = queryInfo.tokens.filter(token => text.includes(token)).length
                if (tokenHits === queryInfo.tokens.length) score = 75
                else if (tokenHits > 0) score = 20 * tokenHits
            }
            const lengthPenalty = Math.max(0, text.split(' ').length - queryInfo.tokens.length) * 2
            score -= lengthPenalty
            if (score > best) best = score
        }
        return best
    }

    private extractMangaId(href: string): string | null {
        const idMatch = href.match(this.patterns.mangaId)
        return idMatch ? idMatch[1] : null
    }

    private extractImageUrl(element: any): string | undefined {
        const imgElement = element.find(this.selectors.search.image)
        if (imgElement.length() === 0) return undefined
        const src = String(imgElement.attr("data-src") || imgElement.attr("src") || "").trim()
        if (!src) return undefined
        if (src.startsWith("//")) return "https:" + src
        if (src.startsWith("/")) return this.baseUrl + src
        return src
    }

    private normalizeText(value: string): string {
        return String(value || '')
            .normalize('NFD')
            .replace(/[\u0300-\u036f]/g, '')
            .toLowerCase()
            .replace(/[^a-z0-9]+/g, ' ')
            .trim()
    }

    async findChapters(mangaId: string): Promise<ChapterDetails[]> {
        if (!this.isValidMangaId(mangaId)) return []
        try {
            const mangaUrl = `${this.baseUrl}/manga/${mangaId}/`
            const response = await this.fetchWithRetry(mangaUrl)
            if (!response) return []
            const html = await response.text()
            const $ = LoadDoc(html)
            const direct = this.parseChapters($(this.selectors.chapters.listingWrap))
            const fallback = this.parseChapters($(this.selectors.chapters.list))
            const merged = this.mergeChapters(direct, fallback)
            return this.sortAndIndexChapters(merged)
        } catch {
            return []
        }
    }

    private isValidMangaId(mangaId: string): boolean {
        return typeof mangaId === 'string' && /^[a-z0-9-]+$/i.test(mangaId)
    }

    private parseChapters(elements: any): ChapterDetails[] {
        const chapters: ChapterDetails[] = []
        if (!elements || elements.length() === 0) return chapters
        elements.each((_: number, element: any) => {
            const chapterDetails = this.parseChapterElement(element)
            if (chapterDetails) chapters.push(chapterDetails)
        })
        return chapters
    }

    private parseChapterElement(element: any): ChapterDetails | null {
        const linkElement = element.find(this.selectors.chapters.link)
        if (linkElement.length() === 0) return null
        const title = String(linkElement.text() || "").trim()
        const href = String(linkElement.attr("href") || "").trim()
        if (!title || !href) return null
        const chapterSlugToken = this.extractChapterTokenFromUrl(href)
        if (!chapterSlugToken) return null
        const chapterField = this.normalizeChapterField(chapterSlugToken)
        const sortValue = this.chapterSortValue(chapterSlugToken)
        return {
            id: href,
            url: href,
            title,
            chapter: chapterField,
            index: sortValue,
            language: "pt-BR",
        }
    }

    private extractChapterTokenFromUrl(href: string): string | null {
        const urlMatch = href.match(this.patterns.chapterUrl)
        return urlMatch ? String(urlMatch[1]).trim() : null
    }

    private normalizeChapterField(token: string): string {
        return token.replace(/_/g, '.')
    }

    private chapterSortValue(token: string): number {
        const parts = token.split('_')
        const main = parseFloat(parts[0].replace(',', '.'))
        if (!Number.isFinite(main)) return Number.MAX_SAFE_INTEGER
        if (parts.length === 1) return main
        const suffixNum = parseInt(parts[1], 10)
        if (!Number.isFinite(suffixNum)) return main
        return main + suffixNum / 1000
    }

    private mergeChapters(...groups: ChapterDetails[][]): ChapterDetails[] {
        const map = new Map<string, ChapterDetails>()
        for (const group of groups) {
            for (const chapter of group) {
                if (!map.has(chapter.url)) map.set(chapter.url, chapter)
            }
        }
        return Array.from(map.values())
    }

    private sortAndIndexChapters(chapters: ChapterDetails[]): ChapterDetails[] {
        chapters.sort((a, b) => a.index - b.index)
        return chapters.map((chapter, index) => ({ ...chapter, index }))
    }

    async findChapterPages(chapterId: string): Promise<ChapterPage[]> {
        if (!this.isValidChapterId(chapterId)) return []
        try {
            const response = await this.fetchWithRetry(chapterId)
            if (!response) return []
            const html = await response.text()
            const $ = LoadDoc(html)
            return this.parseChapterPages($, chapterId)
        } catch {
            return []
        }
    }

    private isValidChapterId(chapterId: string): boolean {
        return typeof chapterId === 'string' && chapterId.startsWith('http')
    }

    private parseChapterPages($: any, chapterUrl: string): ChapterPage[] {
        const pageSelectors = [
            this.selectors.pages.content,
            this.selectors.pages.reading,
            this.selectors.pages.page
        ]
        let elements: any = null
        for (const selector of pageSelectors) {
            elements = $(selector)
            if (elements.length() > 0) break
        }
        if (!elements || elements.length() === 0) return []
        const results: ChapterPage[] = []
        const seen = new Set<string>()
        elements.each((index: number, element: any) => {
            const pageUrl = this.extractPageImageUrl(element)
            if (pageUrl && !seen.has(pageUrl)) {
                seen.add(pageUrl)
                results.push({
                    url: pageUrl,
                    index,
                    headers: {
                        'Referer': chapterUrl,
                        'User-Agent': this.defaultHeaders['User-Agent'],
                    },
                })
            }
        })
        return results
    }

    private extractPageImageUrl(element: any): string | null {
        const src = String(element.attr('data-src') || element.attr('src') || '').trim()
        if (!src) return null
        if (src.startsWith('//')) return 'https:' + src
        if (src.startsWith('/')) return this.baseUrl + src
        return src
    }
}

class TiaManhwaProvider {
    private readonly baseUrl = "https://tiamanhwa.com"

    private readonly selectors = {
        searchContainers: ".search-wrap .c-tabs-item, .c-tabs-item, .page-item-detail, .row.c-tabs-item",
        searchTitles: "h3 a, .post-title h3 a, .post-title a, h2 a",
        searchImages: "img",
        chapterRows: ".listing-chapters_wrap li.wp-manga-chapter, .main li.wp-manga-chapter, li.wp-manga-chapter",
        pageImages: [
            ".reading-content img.wp-manga-chapter-img",
            ".page-break img.wp-manga-chapter-img",
            ".reading-content img",
            "img.wp-manga-chapter-img"
        ]
    }

    private readonly defaultHeaders = {
        "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/122.0.0.0 Safari/537.36",
        "Accept": "text/html,application/xhtml+xml,application/xml;q=0.9,image/webp,*/*;q=0.8"
    }

    private readonly patterns = {
        mangaId: /\/manhwa\/([^\/]+)\/?/i,
        chapterUrl: /\/capitulo-([^\/]+)\/?/i,
        chapterTitle: /cap[íi]tulo\s*([0-9]+(?:[\.,_][0-9]+)?)/i
    }

    async search(opts: QueryOptions): Promise<SearchResult[]> {
        const query = String(opts?.query || '').trim()
        if (!query) return []

        try {
            const urls = [
                `${this.baseUrl}/?s=${encodeURIComponent(query)}&post_type=wp-manga`,
                `${this.baseUrl}/?s=${encodeURIComponent(query)}&post_type=manga`
            ]

            const queryInfo = this.buildQueryInfo(query)
            const resultsMap = new Map<string, { item: SearchResult; score: number }>()

            for (const searchUrl of urls) {
                const response = await this.fetchWithRetry(searchUrl)
                if (!response) continue
                const html = await response.text()
                const $ = LoadDoc(html)

                $(this.selectors.searchContainers).each((_: number, element: any) => {
                    const item = this.parseSearchResultItem(element)
                    if (!item) return
                    const score = this.scoreResult(item, queryInfo)
                    if (score < 85) return
                    const current = resultsMap.get(item.id)
                    if (!current || score > current.score) {
                        resultsMap.set(item.id, { item, score })
                    }
                })

                $("a[href*='/manhwa/']").each((_: number, element: any) => {
                    const href = String(element.attr("href") || "").trim()
                    let title = String(element.attr("title") || element.text() || "").trim()
                    if (!href || !title || /\/capitulo-/i.test(href)) return
                    if (title.length < 3) return
                    title = this.cleanTitle(title)
                    if (!title || title.length < 3) return

                    const mangaId = this.extractMangaId(href)
                    if (!mangaId) return

                    const item: SearchResult = {
                        id: `tiamanhwa:${mangaId}`,
                        title,
                        synonyms: this.buildSynonyms(title, mangaId),
                        image: undefined,
                    }
                    const score = this.scoreResult(item, queryInfo)
                    if (score < 95) return
                    const current = resultsMap.get(item.id)
                    if (!current || score > current.score) {
                        resultsMap.set(item.id, { item, score })
                    }
                })
            }

            return Array.from(resultsMap.values())
                .sort((a, b) => b.score - a.score)
                .slice(0, 10)
                .map(entry => entry.item)
        } catch {
            return []
        }
    }

    private async fetchWithRetry(url: string, retries: number = 1): Promise<Response | null> {
        for (let attempt = 0; attempt <= retries; attempt++) {
            try {
                const response = await fetch(url, { headers: this.defaultHeaders, redirect: 'follow' })
                if (response.ok) return response
                if (attempt === retries) return null
            } catch {
                if (attempt === retries) return null
            }
        }
        return null
    }

    private parseSearchResultItem(element: any): SearchResult | null {
        const linkElement = element.find(this.selectors.searchTitles)
        if (linkElement.length() === 0) return null

        const href = String(linkElement.attr("href") || "").trim()
        let title = String(linkElement.attr("title") || linkElement.text() || "").trim()
        if (!href || !title || /\/capitulo-/i.test(href)) return null

        const mangaId = this.extractMangaId(href)
        if (!mangaId) return null

        title = this.cleanTitle(title)
        if (!title || title.length < 3) return null

        return {
            id: `tiamanhwa:${mangaId}`,
            title,
            synonyms: this.buildSynonyms(title, mangaId),
            image: this.extractImageUrl(element),
        }
    }

    private cleanTitle(title: string): string {
        return String(title || '')
            .replace(/\s+/g, ' ')
            .replace(/^ler\s+/i, '')
            .replace(/\s+em\s+portugues$/i, '')
            .replace(/\s+portugues$/i, '')
            .trim()
    }

    private extractMangaId(href: string): string | null {
        const match = href.match(this.patterns.mangaId)
        return match ? match[1] : null
    }

    private extractImageUrl(element: any): string | undefined {
        const imgElement = element.find(this.selectors.searchImages)
        if (imgElement.length() === 0) return undefined
        const src = String(imgElement.attr("data-src") || imgElement.attr("src") || "").trim()
        return this.normalizeUrl(src) || undefined
    }

    private buildSynonyms(title: string, mangaId: string): string[] {
        const values = [title, mangaId.replace(/-/g, ' '), mangaId]
        const map = new Map<string, string>()
        for (const value of values) {
            const raw = String(value || '').trim()
            const key = this.normalizeText(raw)
            if (!raw || !key || map.has(key)) continue
            map.set(key, raw)
        }
        return Array.from(map.values())
    }

    private buildQueryInfo(query: string): { normalized: string; tokens: string[] } {
        const normalized = this.normalizeText(query)
        const tokens = normalized.split(' ').filter(token => token.length >= 2)
        return { normalized, tokens }
    }

    private scoreResult(item: SearchResult, queryInfo: { normalized: string; tokens: string[] }): number {
        const texts = [item.title, ...(item.synonyms || [])]
            .map(value => this.normalizeText(String(value || '')))
            .filter(Boolean)
        if (texts.length === 0 || queryInfo.tokens.length === 0) return 0

        let best = 0
        for (const text of texts) {
            let score = 0
            const compactText = text.replace(/\s+/g, '')
            const compactQuery = queryInfo.normalized.replace(/\s+/g, '')
            if (text === queryInfo.normalized) score = 140
            else if (compactText === compactQuery) score = 135
            else if (text.startsWith(queryInfo.normalized)) score = 120
            else if (text.includes(queryInfo.normalized)) score = 110
            else {
                const tokenHits = queryInfo.tokens.filter(token => text.includes(token)).length
                if (tokenHits === queryInfo.tokens.length) score = 92
                else if (tokenHits >= Math.max(2, queryInfo.tokens.length - 1)) score = 70
            }
            const extraWords = Math.max(0, text.split(' ').length - queryInfo.tokens.length)
            score -= extraWords * 4
            if (queryInfo.tokens.length >= 2) {
                const missing = queryInfo.tokens.filter(token => !text.includes(token)).length
                score -= missing * 18
            }
            if (score > best) best = score
        }
        return best
    }

    private normalizeText(value: string): string {
        return String(value || '')
            .normalize('NFD')
            .replace(/[\u0300-\u036f]/g, '')
            .toLowerCase()
            .replace(/[^a-z0-9]+/g, ' ')
            .trim()
    }

    async findChapters(mangaId: string): Promise<ChapterDetails[]> {
        if (!this.isValidMangaId(mangaId)) return []
        try {
            const response = await this.fetchWithRetry(`${this.baseUrl}/manhwa/${mangaId}/`)
            if (response) {
                const html = await response.text()
                const $ = LoadDoc(html)
                const chaptersFromPage = this.extractChaptersFromPage($, mangaId)
                if (chaptersFromPage.length >= 2) {
                    return chaptersFromPage.map((chapter, index) => ({ ...chapter, index }))
                }
            }
            return this.enumerateValidatedChapters(mangaId)
        } catch {
            return this.enumerateValidatedChapters(mangaId)
        }
    }

    private extractChaptersFromPage($: any, mangaId: string): ChapterDetails[] {
        const map = new Map<string, ChapterDetails>()
        $(this.selectors.chapterRows).each((_: number, element: any) => {
            const link = element.find('a').first()
            const href = String(link.attr('href') || '').trim()
            const title = String(link.text() || '').trim()
            const chapter = this.createChapterFromHref(mangaId, href, title)
            if (!chapter) return
            map.set(chapter.chapter, chapter)
        })
        return Array.from(map.values()).sort((a, b) => a.index - b.index)
    }

    private async enumerateValidatedChapters(mangaId: string): Promise<ChapterDetails[]> {
        const chapters: ChapterDetails[] = []
        let misses = 0
        const maxMisses = 4
        const maxChapters = 30
        for (let num = 1; num <= maxChapters; num++) {
            const url = `${this.baseUrl}/manhwa/${mangaId}/capitulo-${num}/`
            const validated = await this.validateChapterPage(url, mangaId, String(num))
            if (!validated) {
                misses++
                if (misses >= maxMisses && chapters.length > 0) break
                continue
            }
            chapters.push(validated)
            misses = 0
        }
        return chapters.map((chapter, index) => ({ ...chapter, index }))
    }

    private async validateChapterPage(url: string, mangaId: string, expectedChapter: string): Promise<ChapterDetails | null> {
        const response = await this.fetchWithRetry(url)
        if (!response) return null

        const finalUrl = String((response as any).url || url)
        const finalMangaId = this.extractMangaId(finalUrl)
        const finalToken = this.extractChapterTokenFromUrl(finalUrl)
        if (!finalMangaId || finalMangaId !== mangaId) return null
        if (!finalToken || finalToken !== expectedChapter) return null

        const html = await response.text()
        const $ = LoadDoc(html)
        const titleText = String($('title').first().text() || $('h1').first().text() || '').trim()
        const titleMatch = titleText.match(this.patterns.chapterTitle)
        if (titleMatch) {
            const foundChapter = titleMatch[1].replace(/,/g, '.').replace(/_/g, '.')
            if (foundChapter !== expectedChapter) return null
        }

        let imageCount = 0
        for (const selector of this.selectors.pageImages) {
            imageCount = $(selector).length()
            if (imageCount > 0) break
        }
        if (imageCount === 0) return null

        return {
            id: finalUrl,
            url: finalUrl,
            title: `Capítulo ${expectedChapter}`,
            chapter: expectedChapter,
            index: parseFloat(expectedChapter),
            language: 'pt-BR',
        }
    }

    private createChapterFromHref(mangaId: string, href: string, title: string): ChapterDetails | null {
        if (!href || !/\/capitulo-/i.test(href)) return null
        const hrefMangaId = this.extractMangaId(href)
        if (!hrefMangaId || hrefMangaId !== mangaId) return null
        const token = this.extractChapterTokenFromUrl(href)
        if (!token) return null
        const chapter = token.replace(/_/g, '.').replace(/,/g, '.')
        return {
            id: href,
            url: href,
            title: title || `Capítulo ${chapter}`,
            chapter,
            index: this.chapterSortValue(token),
            language: 'pt-BR',
        }
    }

    private isValidMangaId(mangaId: string): boolean {
        return typeof mangaId === 'string' && /^[a-z0-9-]+$/i.test(mangaId)
    }

    private extractChapterTokenFromUrl(href: string): string | null {
        const match = href.match(this.patterns.chapterUrl)
        return match ? String(match[1]).trim() : null
    }

    private chapterSortValue(token: string): number {
        const parts = String(token || '').replace(/,/g, '.').split('_')
        const main = parseFloat(parts[0])
        if (!Number.isFinite(main)) return Number.MAX_SAFE_INTEGER
        if (parts.length === 1) return main
        const suffixNum = parseInt(parts[1], 10)
        if (!Number.isFinite(suffixNum)) return main
        return main + suffixNum / 10
    }

    async findChapterPages(chapterId: string): Promise<ChapterPage[]> {
        if (!this.isValidChapterId(chapterId)) return []
        try {
            const response = await this.fetchWithRetry(chapterId)
            if (!response) return []
            const html = await response.text()
            const $ = LoadDoc(html)
            const pages: ChapterPage[] = []
            const seen = new Set<string>()
            let idx = 0
            for (const selector of this.selectors.pageImages) {
                $(selector).each((_: number, element: any) => {
                    const src = String(element.attr("data-src") || element.attr("src") || "").trim()
                    const imageUrl = this.normalizeUrl(src)
                    if (!imageUrl || seen.has(imageUrl)) return
                    seen.add(imageUrl)
                    pages.push({
                        url: imageUrl,
                        index: idx++,
                        headers: {
                            Referer: chapterId,
                            "User-Agent": this.defaultHeaders["User-Agent"],
                        },
                    })
                })
                if (pages.length > 0) break
            }
            return pages
        } catch {
            return []
        }
    }

    private isValidChapterId(chapterId: string): boolean {
        return typeof chapterId === 'string' && chapterId.startsWith('http')
    }

    private normalizeUrl(url: string): string | null {
        const value = String(url || '').trim()
        if (!value) return null
        if (value.startsWith('//')) return 'https:' + value
        if (value.startsWith('/')) return this.baseUrl + value
        return value
    }
}
